import { supabase } from './supabase'

/**
 * Submit a comment for a post.
 * @param {string} postId - UUID of the post
 * @param {string} commentText - The comment body
 * @returns {Promise<object|null>} The inserted comment row on success, or null on no-op/failure
 */
export async function handleCommentSubmit(postId: string, commentText: string) {
  if (!commentText || !commentText.trim()) {
    // Nothing to do
    return null
  }

  try {
    // Get current user
    const { data: userData, error: userErr } = await supabase.auth.getUser()
    if (userErr) {
      console.error('[handleCommentSubmit] failed to get user:', userErr)
      return null
    }

    const user = (userData as any)?.user
    if (!user || !user.id) {
      console.error('[handleCommentSubmit] no authenticated user found')
      return null
    }

    // Insert into post_comments (use active flag to match your schema)
    const { data: inserted, error: insertErr } = await supabase
      .from('post_comments')
      .insert({
        post_id: postId,
        user_id: user.id,
        content: commentText.trim(),
        is_active: true
      })
      .select()
      .single()

    if (insertErr) {
      console.error('[handleCommentSubmit] insert error:', insertErr)
      return null
    }

    // Try to clear a possible DOM input element with id `comment-input-<postId>` (graceful)
    try {
      const el = document.getElementById(`comment-input-${postId}`) as HTMLInputElement | HTMLTextAreaElement | null
      if (el) el.value = ''
    } catch (e) {
      // In non-browser contexts (SSR) this will throw; ignore
    }

    return inserted || null
  } catch (e) {
    console.error('[handleCommentSubmit] unexpected error:', e)
    return null
  }
}
