"use client"

import React, { useEffect, useState, useRef } from 'react'
import Link from 'next/link'
import { supabase } from '@/lib/supabase'
import { handleCommentSubmit } from '@/lib/commentService'

type Post = {
  id: string
  content: string
  likes_count: number
  comments_count: number
  created_at: string
  user_full_name?: string
  user_username?: string
  user_profile_image?: string
  user_id?: string
  user_liked?: boolean
}

type Comment = {
  id: string
  content: string
  created_at: string
  author_username?: string
}

export default function CommunityFeed() {
  const [posts, setPosts] = useState<Post[]>([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)
  const [pendingLikes, setPendingLikes] = useState<Record<string, boolean>>({})
  const [commentsOpen, setCommentsOpen] = useState<Record<string, boolean>>({})
  const [commentsByPost, setCommentsByPost] = useState<Record<string, Comment[]>>({})
  const [commentsLoading, setCommentsLoading] = useState<Record<string, boolean>>({})
  const [commentInputs, setCommentInputs] = useState<Record<string, string>>({})
  const realtimeSubs = useRef<Map<string, any>>(new Map())

  useEffect(() => {
    let mounted = true

    async function load() {
      setLoading(true)
      setError(null)

      // Prefer the DB RPC which returns authoritative likes_count and whether
      // the current user has liked each post. This avoids stale server-side cache
      // that can cause likes_count to appear as 0 after page refresh.
      try {
        const { data: rpcPosts, error: rpcError } = await supabase.rpc('get_posts_with_like_details')

        if (!rpcError && Array.isArray(rpcPosts)) {
          if (mounted) setPosts(rpcPosts.map((fp: any) => ({
            id: fp.id,
            content: fp.content,
            likes_count: Number(fp.likes_count || 0),
            comments_count: fp.comments_count || 0,
            created_at: fp.created_at,
            user_full_name: fp.author_username || '',
            user_username: fp.author_username || '',
            user_profile_image: fp.author_profile_image || '',
            user_id: fp.author_id || '',
            user_liked: !!fp.user_has_liked
          })))
        } else {
          // Fallback to the existing handler if RPC fails (keeps backward compatibility)
          const { data: sessionData } = await supabase.auth.getSession()
          const token = sessionData?.session?.access_token
          const headers: Record<string, string> = { 'Content-Type': 'application/json' }
          if (token) headers['Authorization'] = `Bearer ${token}`

          const res = await fetch('/api/supabase/functions/community-handler', {
            method: 'POST',
            headers,
            body: JSON.stringify({ action: 'get-community-posts' })
          })

          const data = await res.json()
          if (!res.ok || !data.success) {
            setError(data?.error || 'Failed to load posts')
            setPosts([])
          } else {
            if (mounted) setPosts(data.posts || [])
          }
        }
      } catch (e) {
        console.error('Failed to fetch posts', e)
        setError('Failed to load posts')
        if (mounted) setPosts([])
      } finally {
        if (mounted) setLoading(false)
      }
    }

    load()
    return () => { mounted = false }
  }, [])

  async function toggleLike(postId: string) {
    // optimistic update
    setPendingLikes(prev => ({ ...prev, [postId]: true }))
    setPosts(prev => prev.map(p => p.id === postId ? ({ ...p, user_liked: !p.user_liked, likes_count: (p.user_liked ? Math.max(0, (p.likes_count || 0) - 1) : (p.likes_count || 0) + 1) }) : p))

    try {
      const { data: sessionData } = await supabase.auth.getSession()
      const token = sessionData?.session?.access_token
      if (!token) {
        // revert optimistic update and prompt sign-in
        setPosts(prev => prev.map(p => p.id === postId ? ({ ...p, user_liked: !p.user_liked, likes_count: (p.user_liked ? Math.max(0, (p.likes_count || 0) - 1) : (p.likes_count || 0) + 1) }) : p))
        setError('Please sign in to like posts.')
        return
      }

      // Use Supabase RPC toggle_like for atomic toggle on the DB side.
      // The RPC returns a boolean indicating the new liked state.
      try {
        const { data, error } = await supabase.rpc('toggle_like', { post_id_to_toggle: postId })

        if (error) {
          console.error('toggle_like RPC returned error:', error)
          // revert optimistic update
          setPosts(prev => prev.map(p => p.id === postId ? ({ ...p, user_liked: !p.user_liked, likes_count: (p.user_liked ? Math.max(0, (p.likes_count || 0) - 1) : (p.likes_count || 0) + 1) }) : p))
          return
        }

        console.log('toggle_like returned:', data)

        // `data` is expected to be a boolean (true if liked after call)
        const serverLiked = Array.isArray(data) ? data[0] : data

        // Refresh authoritative post data for this user by calling the RPC that returns
        // posts with like details. This avoids stale server-side caches of likes_count.
        try {
          const { data: freshPosts, error: freshError } = await supabase.rpc('get_posts_with_like_details')
          if (!freshError && Array.isArray(freshPosts)) {
            // Map RPC rows into our Post type shape and update state
            setPosts(freshPosts.map((fp: any) => ({
              id: fp.id,
              content: fp.content,
              likes_count: Number(fp.likes_count || 0),
              comments_count: fp.comments_count || 0,
              created_at: fp.created_at,
              user_full_name: fp.author_username || '',
              user_username: fp.author_username || '',
              user_profile_image: fp.author_profile_image || '',
              user_id: fp.author_id || '',
              user_liked: !!fp.user_has_liked
            })))
          } else {
            // Fallback: only update the single post's liked state
            setPosts(prev => prev.map(p => p.id === postId ? ({ ...p, user_liked: typeof serverLiked === 'boolean' ? serverLiked : p.user_liked }) : p))
          }
        } catch (e) {
          console.error('Failed to refresh posts after toggle_like:', e)
          // Fallback behavior
          setPosts(prev => prev.map(p => p.id === postId ? ({ ...p, user_liked: typeof serverLiked === 'boolean' ? serverLiked : p.user_liked }) : p))
        }
      } catch (err) {
        console.error('toggle_like RPC call failed:', err)
        // revert optimistic update
        setPosts(prev => prev.map(p => p.id === postId ? ({ ...p, user_liked: !p.user_liked, likes_count: (p.user_liked ? Math.max(0, (p.likes_count || 0) - 1) : (p.likes_count || 0) + 1) }) : p))
      } finally {
        setPendingLikes(prev => { const copy = { ...prev }; delete copy[postId]; return copy })
      }

    } catch (e) {
      console.error('Like failed', e)
      // revert optimistic
      setPosts(prev => prev.map(p => p.id === postId ? ({ ...p, user_liked: !p.user_liked, likes_count: (p.user_liked ? Math.max(0, (p.likes_count || 0) - 1) : (p.likes_count || 0) + 1) }) : p))
      setPendingLikes(prev => { const copy = { ...prev }; delete copy[postId]; return copy })
    }
  }

  // Fetch comments for a post using the RPC we added (get_comments_for_post)
  async function fetchComments(postId: string) {
    setCommentsLoading(prev => ({ ...prev, [postId]: true }))
    try {
      const { data, error } = await supabase.rpc('get_comments_for_post', { post_id_to_fetch: postId })
      if (error) {
        console.error('[fetchComments] RPC error:', error)
        setCommentsByPost(prev => ({ ...prev, [postId]: [] }))
      } else if (Array.isArray(data)) {
        const mapped = data.map((c: any) => ({ id: c.id, content: c.content, created_at: c.created_at, author_username: c.author_username }))
        setCommentsByPost(prev => ({ ...prev, [postId]: mapped }))
        // Keep the posts list in sync with authoritative comment count
        setPosts(prev => prev.map(p => p.id === postId ? ({ ...p, comments_count: mapped.length }) : p))
      } else {
        setCommentsByPost(prev => ({ ...prev, [postId]: [] }))
      }
    } catch (e) {
      console.error('[fetchComments] unexpected error', e)
      setCommentsByPost(prev => ({ ...prev, [postId]: [] }))
    } finally {
      setCommentsLoading(prev => ({ ...prev, [postId]: false }))
    }
  }

  function subscribeToComments(postId: string) {
    // avoid duplicate subscriptions
    if (realtimeSubs.current.has(postId)) return

    const channel = supabase
      .channel(`post_comments:${postId}`)
      .on(
        'postgres_changes',
        { event: 'INSERT', schema: 'public', table: 'post_comments', filter: `post_id=eq.${postId}` },
        (payload) => {
          try {
            const newRow = (payload as any).new
            if (!newRow || !newRow.is_active) return
            const comment: Comment = {
              id: newRow.id,
              content: newRow.content,
              created_at: newRow.created_at,
              author_username: newRow.author_username || newRow.user_id
            }
            setCommentsByPost(prev => {
              const list = prev[postId] || []
              const next = [...list, comment].sort((a,b) => new Date(a.created_at).getTime() - new Date(b.created_at).getTime())
              // increment posts.comments_count to reflect the new comment
              setPosts(ps => ps.map(p => p.id === postId ? ({ ...p, comments_count: (p.comments_count || 0) + 1 }) : p))
              return { ...prev, [postId]: next }
            })
          } catch (e) {
            console.error('[subscribeToComments] handler error', e)
          }
        }
      )
      .subscribe()

    realtimeSubs.current.set(postId, channel)
  }

  async function unsubscribeFromComments(postId: string) {
    const channel = realtimeSubs.current.get(postId)
    if (!channel) return
    try {
      await channel.unsubscribe()
    } catch (e) {
      console.warn('[unsubscribeFromComments] error', e)
    }
    realtimeSubs.current.delete(postId)
  }

  // Toggle comments panel open/close for a post
  async function toggleComments(postId: string) {
    const isOpen = !!commentsOpen[postId]
    if (isOpen) {
      // closing
      setCommentsOpen(prev => ({ ...prev, [postId]: false }))
      await unsubscribeFromComments(postId)
    } else {
      // opening: fetch comments then subscribe
      setCommentsOpen(prev => ({ ...prev, [postId]: true }))
      await fetchComments(postId)
      subscribeToComments(postId)
    }
  }

  // Submit comment for a post
  async function submitComment(postId: string) {
    const text = (commentInputs[postId] || '').trim()
    if (!text) return
    const inserted = await handleCommentSubmit(postId, text)
    if (inserted) {
      // clear input state for controlled inputs
      setCommentInputs(prev => ({ ...prev, [postId]: '' }))
      // append optimistically — realtime will also deliver the new comment
      setCommentsByPost(prev => {
        const list = prev[postId] || []
        const c: Comment = { id: inserted.id, content: inserted.content, created_at: inserted.created_at, author_username: inserted.author_username || '' }
        return { ...prev, [postId]: [...list, c] }
      })
      // update comments count in posts state
      setPosts(prev => prev.map(p => p.id === postId ? ({ ...p, comments_count: (p.comments_count || 0) + 1 }) : p))
    }
  }

  if (loading) return <div className="py-8">Loading posts...</div>
  if (error) return <div className="py-8 text-red-600">{error}</div>

  return (
    <div className="space-y-4">
      {posts.length === 0 && <div className="text-gray-500 py-6">No posts yet — be the first to share!</div>}

      {posts.map(post => (
        <article key={post.id} className="bg-white shadow rounded-lg p-4">
          <div className="flex items-start gap-3">
              <Link href={post.user_id ? `/community/profile/${post.user_id}` : '/profile'} className="h-10 w-10 rounded-full bg-gray-100 overflow-hidden flex items-center justify-center">
                {post.user_profile_image ? <img src={post.user_profile_image} alt="avatar" className="h-full w-full object-cover" /> : <span className="text-sm text-gray-600">{(post.user_full_name || post.user_username || 'U').slice(0,1)}</span>}
              </Link>
            <div className="flex-1">
              <div className="flex items-center justify-between">
                <div>
                  <div className="text-sm font-medium text-gray-800">
                    <Link href={post.user_id ? `/community/profile/${post.user_id}` : '/profile'} className="hover:underline">
                      {post.user_full_name || post.user_username || 'Unknown'}
                    </Link>
                  </div>
                  <div className="text-xs text-gray-500">{new Date(post.created_at).toLocaleString()}</div>
                </div>
              </div>

              <div className="mt-3 text-gray-800 whitespace-pre-wrap">{post.content}</div>

              <div className="mt-4 flex items-center gap-3">
                <button
                  type="button"
                  aria-pressed={post.user_liked}
                  onClick={() => toggleLike(post.id)}
                  disabled={!!pendingLikes[post.id]}
                  className={`flex items-center gap-2 px-3 py-2 rounded-lg transition-colors ${pendingLikes[post.id] ? 'opacity-60 cursor-not-allowed' : 'cursor-pointer'} ${post.user_liked ? 'text-red-600 bg-red-50' : 'text-gray-600 hover:bg-gray-50'}`}
                >
                  <i className={`${post.user_liked ? 'ri-heart-fill' : 'ri-heart-line'}`} />
                  <span className="text-sm">{post.likes_count ?? 0}</span>
                </button>

                <button
                  type="button"
                  onClick={(e) => { e.stopPropagation(); console.log('[CommunityFeed] comment click', post.id); toggleComments(post.id) }}
                  aria-label={`Open comments for post ${post.id}`}
                  className="flex items-center gap-2 text-gray-600 px-2 py-1 rounded-lg hover:bg-gray-50 z-10 pointer-events-auto"
                >
                  <i className="ri-chat-3-line" />
                  <span className="text-sm">{post.comments_count ?? 0}</span>
                </button>
              </div>
            </div>
          </div>
          {/* Comments panel */}
          {commentsOpen[post.id] && (
            <div className="mt-3 border-t pt-3">
              {commentsLoading[post.id] ? (
                <div className="text-sm text-gray-500">Loading comments...</div>
              ) : (
                <div className="space-y-2">
                  {(commentsByPost[post.id] || []).map(c => (
                    <div key={c.id} className="py-2 flex items-start gap-3">
                      <div className="flex-1">
                        <div className="text-sm font-medium text-gray-800">{c.author_username || 'User'}</div>
                        <div className="text-sm text-gray-700 whitespace-pre-wrap">{c.content}</div>
                        <div className="text-xs text-gray-400">{new Date(c.created_at).toLocaleString()}</div>
                      </div>
                    </div>
                  ))}

                  <div className="pt-2">
                    <textarea
                      id={`comment-input-${post.id}`}
                      value={commentInputs[post.id] || ''}
                      onChange={(e) => setCommentInputs(prev => ({ ...prev, [post.id]: e.target.value }))}
                      placeholder="Write a comment..."
                      className="w-full border rounded-md p-2 text-sm"
                      rows={2}
                    />
                    <div className="mt-2 text-right">
                      <button
                        type="button"
                        onClick={() => submitComment(post.id)}
                        className="px-3 py-1 bg-green-600 text-white rounded-md text-sm"
                      >
                        Comment
                      </button>
                    </div>
                  </div>
                </div>
              )}
            </div>
          )}
        </article>
      ))}
    </div>
  )
}
